<template><div class="overlay"><b>{{ editor.statusText }}</b><div v-if="p" class="small">长度 {{ p.length.toFixed(1) }}m · 坡度 {{ p.slope.toFixed(1) }}% · 最小半径 {{ finite(p.minRadius) }}</div><div v-if="p" class="small">{{ p.reason }}</div><div v-if="editor.hoveredSegmentId" class="small">Hover: {{ editor.hoveredSegmentId }}</div><div class="small">ESC 取消 · Ctrl+Z 撤销 · Ctrl+Y 重做</div></div></template>
<script setup lang="ts">import { computed } from 'vue'; import { useEditorStore } from '../stores/editorStore'; const editor=useEditorStore(); const p=computed(()=>editor.preview); function finite(v:number){ return Number.isFinite(v)?`${v.toFixed(1)}m`:'∞' }</script>
